import{_ as o,o as a,c,a3 as i}from"./chunks/framework.aYYe0dfI.js";const g=JSON.parse('{"title":"Module config:load","description":"config:load 模块负责将 Clore 工具的配置从外部源加载到内存中，提供两个公开接口：load_config 从文件路径加载，load_config_from_string 从字符串直接加载。两者均返回一个整数结果码，指示加载成功或失败，后续可配合 config:validate 确认配置有效性。在内部，模块解析 TOML 格式内容，拒绝未知顶层键，并将原始数据转换为 RawTaskConfig 结构，依赖 config:schema 定义的类型以及 support 模块的文件读写与文本处理能力，确保配置加载过程的正确性与可移植性。","frontmatter":{"title":"Module config:load","description":"config:load 模块负责将 Clore 工具的配置从外部源加载到内存中，提供两个公开接口：load_config 从文件路径加载，load_config_from_string 从字符串直接加载。两者均返回一个整数结果码，指示加载成功或失败，后续可配合 config:validate 确认配置有效性。在内部，模块解析 TOML 格式内容，拒绝未知顶层键，并将原始数据转换为 RawTaskConfig 结构，依赖 config:schema 定义的类型以及 support 模块的文件读写与文本处理能力，确保配置加载过程的正确性与可移植性。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/config/load.md","filePath":"zh/clore/modules/config/load.md"}'),d={name:"zh/clore/modules/config/load.md"};function t(r,e,l,n,s,f){return a(),c("div",null,[...e[0]||(e[0]=[i('<h1 id="module-config-load" tabindex="-1">Module <code>config:load</code> <a class="header-anchor" href="#module-config-load" aria-label="Permalink to &quot;Module `config:load`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>config:load</code> 模块负责将 Clore 工具的配置从外部源加载到内存中，提供两个公开接口：<code>load_config</code> 从文件路径加载，<code>load_config_from_string</code> 从字符串直接加载。两者均返回一个整数结果码，指示加载成功或失败，后续可配合 <code>config:validate</code> 确认配置有效性。在内部，模块解析 TOML 格式内容，拒绝未知顶层键，并将原始数据转换为 <code>RawTaskConfig</code> 结构，依赖 <code>config:schema</code> 定义的类型以及 <code>support</code> 模块的文件读写与文本处理能力，确保配置加载过程的正确性与可移植性。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./schema"><code>config:schema</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-config-configerror" tabindex="-1"><code>clore::config::ConfigError</code> <a class="header-anchor" href="#clore-config-configerror" aria-label="Permalink to &quot;`clore::config::ConfigError`&quot;">​</a></h3><p>Declaration: <code>config/load.cppm:15</code></p><p>Definition: <code>config/load.cppm:15</code></p><p>Declaration: <a href="./../../namespaces/clore/config/"><code>Namespace clore::config</code></a></p><p>结构 <code>clore::config::ConfigError</code> 内部仅包含一个 <code>std::string message</code> 成员，作为错误信息的载体。没有自定义构造函数、析构函数或赋值运算符，因此编译器会隐式生成这些特殊成员，使得该类型是一个可平凡复制、可移动的聚合类型。唯一的隐式不变量是 <code>message</code> 成员始终处于 <code>std::string</code> 所保证的有效状态（可为空字符串），不添加额外的约束或状态校验。所有对于该错误信息的访问和修改均直接通过公有成员 <code>message</code> 进行，无需依赖任何内部辅助函数或复杂的数据结构。</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li><code>message</code> 应当包含有意义的错误描述</li><li>结构体无其他状态约束</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>message</code> 成员</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>在配置解析失败时构造并返回该错误</li><li>用户通过读取 <code>message</code> 获取错误信息</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-config-load-config" tabindex="-1"><code>clore::config::load_config</code> <a class="header-anchor" href="#clore-config-load-config" aria-label="Permalink to &quot;`clore::config::load_config`&quot;">​</a></h3><p>Declaration: <code>config/load.cppm:19</code></p><p>Definition: <code>config/load.cppm:81</code></p><p>Declaration: <a href="./../../namespaces/clore/config/"><code>Namespace clore::config</code></a></p><p>该函数首先将传入的 <code>path</code> 转换为绝对路径并规范化，然后检查文件是否存在，若不存在则立即返回带有 <code>ConfigError</code> 的意外结果。文件存在时，依赖 <code>clore::support::read_utf8_text_file</code> 读取其完整内容为 <code>content</code>；读取失败同样返回错误。随后将 <code>content</code> 委托给 <code>load_config_from_string</code> 进行解析，后者内部通过 TOML 解析器加载 <code>toml_content</code> 表，校验顶层键的合法性（依赖 <code>reject_unknown_top_level_keys</code>），并构造 <code>RawTaskConfig</code> 结构，再经由 <code>to_config</code> 转换为最终配置对象。解析成功后，函数用 <code>config_path.parent_path</code> 字符串填充结果中的 <code>workspace_root</code> 字段，从而完成配置加载。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>reads a configuration file from the filesystem</li><li>checks existence of the file via <code>std::filesystem::exists</code></li><li>reads the content of the file using <code>clore::support::read_utf8_text_file</code></li><li>sets the <code>workspace_root</code> field of the returned <code>TaskConfig</code> object</li></ul><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>the <code>path</code> parameter</li><li>the filesystem via <code>std::filesystem::exists</code></li><li>the file content via <code>clore::support::read_utf8_text_file</code></li><li>the result of <code>load_config_from_string</code></li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>the <code>workspace_root</code> field of the returned <code>TaskConfig</code> object</li><li>the error state returned as <code>std::unexpected</code> (if any)</li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>loading application configuration from a configuration file at startup</li><li>part of a configuration subsystem to parse config files with relative path resolution</li></ul><h3 id="clore-config-load-config-from-string" tabindex="-1"><code>clore::config::load_config_from_string</code> <a class="header-anchor" href="#clore-config-load-config-from-string" aria-label="Permalink to &quot;`clore::config::load_config_from_string`&quot;">​</a></h3><p>Declaration: <code>config/load.cppm:21</code></p><p>Definition: <code>config/load.cppm:110</code></p><p>Declaration: <a href="./../../namespaces/clore/config/"><code>Namespace clore::config</code></a></p><p>该函数首先对输入的 <code>toml_content</code> 执行 BOM 剥离（调用 <code>clore::support::strip_utf8_bom</code>），再将结果传入 <code>::toml::parse</code> 进行解析。解析成功后会调用 <code>reject_unknown_top_level_keys</code> 校验表内是否存在未被 <code>RawTaskConfig</code> 字段覆盖的顶层键；若发现未知键则立即返回 <code>ConfigError</code>。随后通过 <code>toml_codec::from_toml</code> 将 <code>table</code> 解码为 <code>RawTaskConfig</code> 的实例 <code>raw</code>，该步骤若失败同样以 <code>ConfigError</code> 形式返回。最终调用 <code>to_config</code> 将 <code>raw</code> 转换为 <code>TaskConfig</code> 并作为 <code>std::expected</code> 的成功值返回。</p><p>整个函数完全依赖 <code>std::expected</code> 进行错误传播，未使用异常。错误处理覆盖三个节点：TOML 语法错误（<code>::toml::parse_error</code>）、未知顶层键（<code>reject_unknown_top_level_keys</code> 返回的 <code>ConfigError</code>）以及 <code>toml_codec::from_toml</code> 的字段级解码失败，每种情况均生成包含描述性消息的 <code>ConfigError</code>。核心依赖包括 <code>kota::codec::toml</code>（TOML 序列化/反序列化）、<code>::toml</code>（解析库）以及 <code>clore::support::strip_utf8_bom</code>（BOM 清理）。</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>parameter <code>toml_content</code> (<code>std::string_view</code>)</li><li>global function <code>clore::support::strip_utf8_bom</code></li><li>global function <code>reject_unknown_top_level_keys</code></li><li>global function <code>toml_codec::from_toml</code></li><li>global function <code>to_config</code></li><li>TOML library internals</li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>local variable <code>normalized_toml</code></li><li>local variable <code>table</code></li><li>local variable <code>raw</code></li><li>local variable <code>result</code></li><li>return value (<code>std::expected&lt;TaskConfig, ConfigError&gt;</code>)</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called with a string containing TOML content</li><li>used in config loaders that receive configuration as text</li><li>part of the <code>clore::config</code> API for parsing configuration strings</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>模块 <code>config:load</code> 实现了从文件路径或内存字符串加载 TOML 格式配置的功能。它对外暴露 <code>load_config</code> 和 <code>load_config_from_string</code> 两个入口函数，它们均接受 <code>std::string_view</code> 并返回 <code>int</code> 状态码，后续可配合 <code>config:validate</code> 进行校验。模块通过 <code>import config:schema</code> 引入 <code>TaskConfig</code> 等核心类型，并利用 <code>import support</code> 中的文件读取与文本处理工具来获取原始 TOML 内容。</p><p>内部实现采用匿名命名空间进行分层：先通过 <code>RawTaskConfig</code> 结构体（包含 <code>llm</code> 与 <code>filter</code> 字段）暂存原始解析结果，再经 <code>to_config</code> 转换为成熟配置。解析过程中使用 <code>reject_unknown_top_level_keys</code> 对顶层键进行白名单校验，保证配置的严谨性。这种设计将底层 TOML 表的遍历、键值验证与上层配置对象的构建相分离，使得模块结构清晰、职责单一。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./schema">Module config:schema</a></li><li><a href="./../support/">Module support</a></li></ul>',50)])])}const h=o(d,[["render",t]]);export{g as __pageData,h as default};
